INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd5777978-0088-40b3-bf6f-7e905dc5d62c',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Sweeps — Hyperparameter Search Without the Boilerplate$escape$,
  $escape$wandb Sweeps automate hyperparameter search across your training runs, logging every trial to a shared project so you can compare results in one place. Define a sweep config with a search strategy — `grid`, `random`, or `bayes` — and wandb handles agent scheduling, early termination via `HyperbandEarlyStopper`, and result aggregation automatically.

The Bayesian strategy uses a Gaussian process to model the loss surface, prioritizing promising regions rather than sampling blindly. This converges faster than random search on most deep learning workloads.

Each agent calls your training function, which reads hyperparams via `wandb.config` — no argparse plumbing needed. Parallel agents share the same sweep ID, so you can distribute across GPUs or machines with a single `wandb agent <sweep_id>` command.

After runs complete, use `wandb.Api().sweep(sweep_id).best_run()` programmatically to pull the top checkpoint, or open the Sweep dashboard to view parallel coordinates plots that reveal which params actually drive your metric. Pin the best run to a wandb Report to share findings with your team without exporting a single CSV.$escape$,
  $escape$import wandb

sweep_config = {
    "method": "bayes",
    "metric": {"name": "val_loss", "goal": "minimize"},
    "early_terminate": {"type": "hyperband", "min_iter": 3},
    "parameters": {
        "lr":        {"distribution": "log_uniform_values", "min": 1e-5, "max": 1e-2},
        "dropout":   {"values": [0.1, 0.3, 0.5]},
        "batch_size":{"values": [32, 64, 128]},
    },
}

def train():
    with wandb.init() as run:
        cfg = run.config
        model = build_model(dropout=cfg.dropout)
        optimizer = torch.optim.AdamW(model.parameters(), lr=cfg.lr)
        for epoch in range(20):
            loss = run_epoch(model, optimizer, cfg.batch_size)
            wandb.log({"val_loss": loss, "epoch": epoch})

sweep_id = wandb.sweep(sweep_config, project="my-project")
wandb.agent(sweep_id, function=train, count=30)$escape$,
  $escape$python$escape$,
