INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '09f48ffd-3bc3-4dda-bf20-66bf14e42c3a',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Sweeps — Grid vs Random vs Bayesian Search and Early Stopping$escape$,
  $escape$wandb Sweeps gives you three search strategies via `method` in your sweep config. `grid` exhaustively tries every parameter combination — only viable with small, discrete search spaces. `random` samples combinations independently; it outperforms grid when some parameters matter far more than others. `bayes` uses a Gaussian Process to model the objective surface, selecting next runs by expected improvement — the right default for most deep learning sweeps with continuous parameters.

Early stopping is controlled by the `early_terminate` block. `hyperband` is the standard choice: set `min_iter` to the minimum epochs before termination is considered, and `eta` (default 3) as the bracket reduction factor. Runs in the bottom 1/eta bracket are killed at each rung.

Initiate a sweep with `wandb.sweep(config, project='my-project')` — this returns a `sweep_id`. Launch agents with `wandb.agent(sweep_id, function=train, count=50)`. Each agent calls `wandb.config` to read its assigned hyperparameters, and `wandb.log({'val_loss': loss})` to report the metric Sweeps optimizes against.$escape$,
  $escape$import wandb

sweep_config = {
    "method": "bayes",
    "metric": {"name": "val_loss", "goal": "minimize"},
    "early_terminate": {"type": "hyperband", "min_iter": 5, "eta": 3},
    "parameters": {
        "lr":      {"distribution": "log_uniform_values", "min": 1e-5, "max": 1e-2},
        "dropout": {"values": [0.1, 0.3, 0.5]},
        "epochs":  {"value": 30},
    },
}

def train():
    run = wandb.init()
    cfg = run.config
    for epoch in range(cfg.epochs):
        loss = model.fit(lr=cfg.lr, dropout=cfg.dropout)
        wandb.log({"val_loss": loss, "epoch": epoch})

sweep_id = wandb.sweep(sweep_config, project="my-project")
wandb.agent(sweep_id, function=train, count=40)$escape$,
  $escape$python$escape$,
