INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ce0b11bb-f7c8-4dd2-bd72-fef549011c56',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb Artifacts as a Feature Store — Versioning Offline Features with Full Lineage$escape$,
  $escape$Feature stores split features into offline (batch, historical, used for training) and online (low-latency, used at inference). wandb Artifacts cover the offline side natively — version your feature DataFrames as `type="dataset"` artifacts using `wandb.Table`, and every training run records exactly which feature snapshot it consumed via `run.use_artifact()`. Attach metadata (row counts, column list, pipeline git hash) directly to the artifact so the W&B Registry becomes queryable for drift audits or snapshot rollbacks.

For online features, wandb doesn't run a low-latency key-value store — pair it with Redis or Feast for that layer — but log the feature schema and summary statistics to the same artifact so offline and online definitions stay in sync.

The canonical wandb pattern: a dedicated `job_type="feature-engineering"` run produces and logs the artifact; all downstream `job_type="train"` runs call `run.use_artifact("user-features:latest")`. The full producer-consumer DAG appears in the Artifacts lineage graph, giving you an audit trail from raw data to deployed model checkpoint without a separate feature registry.$escape$,
  $escape$import wandb, pandas as pd

# Feature engineering — produce offline features
run = wandb.init(project="mlops-demo", job_type="feature-engineering")
artifact = wandb.Artifact("user-features", type="dataset",
                          metadata={"features": ["clicks", "dwell_time", "recency"]})
artifact.add(wandb.Table(dataframe=compute_features()), "offline")
run.log_artifact(artifact)
run.finish()

# Training — consume exact versioned snapshot
run = wandb.init(project="mlops-demo", job_type="train")
table = run.use_artifact("user-features:latest").get("offline")
X = pd.DataFrame(data=table.data, columns=table.columns)$escape$,
  $escape$python$escape$,
