INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7cc02f60-ad71-471e-ab95-fbda1a3f34dc',
  '00000000-0000-0000-0000-000000000001',
  $escape$wandb A/B Testing Models — Shadow Deployments, Canary Releases, and Champion/Challenger$escape$,
  $escape$wandb's Model Registry makes champion/challenger workflows first-class. Tag your production model as `champion` and candidates as `challenger` using `run.link_model()` with aliases. For shadow deployments, log both models' predictions to the same run using separate namespaces — `wandb.log({"champion/latency": ..., "challenger/latency": ...})` — so you get side-by-side metric charts without serving challenger traffic to real users.

For canary releases, use `wandb.Api()` to programmatically fetch the challenger artifact, route a percentage of traffic to it, and log outcomes back to a shared project. Compare challenger vs champion using `wandb.plot.line_series()` on a shared dashboard panel.

Promote the winner with `artifact.aliases.append('champion')` and remove the old alias — Registry tracks the full lineage. Use `wandb.alert()` to trigger Slack notifications if challenger diverges on key metrics like F1 or p95 latency. The entire experiment history, including data splits and hyperparameters, stays linked via the artifact graph.$escape$,
  $escape$import wandb

api = wandb.Api()

# Fetch champion and challenger from Model Registry
champion = api.artifact("my-org/model-registry/classifier:champion")
challenger = api.artifact("my-org/model-registry/classifier:challenger")

with wandb.init(project="ab-test", job_type="shadow-eval") as run:
    run.use_artifact(champion)
    run.use_artifact(challenger)

    for batch in eval_batches:
        champ_pred = champion_model.predict(batch)
        chal_pred = challenger_model.predict(batch)
        run.log({
            "champion/f1": f1(champ_pred, batch.labels),
            "challenger/f1": f1(chal_pred, batch.labels),
        })

    # Promote if challenger wins
    if challenger_f1 > champion_f1:
        challenger.aliases.append("champion")
        challenger.save()
        wandb.alert(title="New Champion Promoted", text=f"challenger f1={challenger_f1:.3f}")$escape$,
  $escape$python$escape$,
